code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();

        assert (1 <= n && n <= 100);

        int[][] mat = new int[n][n];
        int val = 1;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                mat[i][j] = val++;
            }
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                System.out.print(mat[i][j] + " ");
            }
            System.out.println();
        }
    }
}

code.JavaScript:
function generateMatrix(n) {
    // Validate the input constraint
    if (n < 1 || n > 100) {
        throw new Error("n must be between 1 and 100");
    }

    // Initialize the matrix with sequential values
    const mat = [];
    let val = 1;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            mat.push(val++);
        }
    }

    // Print all elements in a single line separated by spaces
    console.log(mat.join(' '));
}
